  function setTabs(){['modePick','doneTab','rawTab'].forEach(function(id){var el=$('#'+id);if(el)el.classList.remove('on')});var id=view==='raw'?'rawTab':view==='done'?'doneTab':'modePick';var el=$('#'+id);if(el)el.classList.add('on')}
  function doneForGroup(g){var k=[typeof dateText==='function'?dateText():'',typeof cellText==='function'?cellText():'',typeof typeFilter!=='undefined'&&typeFilter?typeFilter:'ALLTYPE',(typeof store!=='undefined'&&store)?store:'ALLSTORE',g.brand,g.size,g.code||g.sku,g.type].join('|');return num((typeof done!=='undefined'&&done)?done[k]:0)}
  function drawPick(rs,onlyDone){var gs=pickGroups(rs);if(onlyDone)gs=gs.filter(function(g){return doneForGroup(g)>0});var totalPages=Math.max(1,Math.ceil(gs.length/size));if(page>totalPages)page=totalPages;var shown=gs.slice((page-1)*size,page*size);var html='<thead><tr><th>#</th><th>แบรนด์/ไซซ์</th><th>SKU</th><th>สินค้า</th><th>ร้านที่คีย์</th><th>บิล</th><th>จำนวนรวม</th><th>จัดแล้ว</th><th>คงเหลือ</th><th>ยอด</th></tr></thead><tbody>';shown.forEach(function(g,i){var d=doneForGroup(g), rem=g.qty-d, k=keyPick(g);html+='<tr><td>'+(((page-1)*size)+i+1)+'</td><td>'+esc(g.brand)+'<br><small>'+esc(g.size)+' · '+esc(g.type)+'</small></td><td>'+esc(g.code||'-')+'</td><td class="p"><b>'+esc(g.sku||'-')+'</b><small>'+fmt(g.qty)+' ชิ้น · '+fmt(g.stores.size)+' ร้านที่คีย์</small></td><td>'+fmt(g.stores.size)+'</td><td>'+fmt(g.bills.size)+'</td><td>'+fmt(g.qty)+'</td><td><input class="pick" data-k="'+esc(k)+'" type="number" inputmode="numeric" value="'+(d||'')+'"></td><td class="'+(rem<0?'bad':'good')+'">'+fmt(rem)+'</td><td>'+baht(g.amt)+'</td></tr>'});if(!shown.length)html+='<tr><td colspan="10" class="empty">ไม่พบรายการตามตัวกรอง</td></tr>';html+='</tbody>';return {html:html,total:gs.length,groups:gs}}
