  function draw(){safe(function(){if(!hasRows())return;var up=$('#upload'), work=$('#work'), bill=$('#bill');if(up){up.hidden=false;up.classList.remove('hidden')}if(work){work.hidden=false;work.classList.remove('hidden')}if(bill)bill.classList.add('hidden');syncFilters();setTabs();var rs=filtered(), picked=drawPick(rs,false), result=view==='raw'?drawRaw(rs):view==='done'?drawPick(rs,true):picked;if($('#table'))$('#table').innerHTML=result.html;var g=picked.groups,totalQty=g.reduce(function(s,x){return s+num(x.qty)},0),doneQty=g.reduce(function(s,x){return s+doneForGroup(x)},0),remain=Math.max(0,totalQty-doneQty),pct=totalQty?Math.round(doneQty*1000/totalQty)/10:0,amt=rs.reduce(function(s,r){return s+num(r.amt)},0);if($('#amount'))$('#amount').textContent='฿ '+(amt?baht(amt):'—');if($('#doneAmount'))$('#doneAmount').textContent=fmt(doneQty);if($('#remainAmount'))$('#remainAmount').textContent=fmt(remain);if($('#donePct'))$('#donePct').textContent=pct+'%';if($('#doneBar'))$('#doneBar').style.width=Math.min(100,pct)+'%';if($('#tableCount'))$('#tableCount').textContent=(view==='raw'?'รายการดิบ ':'ถอดของ ')+fmt(result.total)+' รายการ';bindPickInputs();drawPager(result.total)},'draw')}
  function drawPager(total){var p=$('.pagination');if(!p)return;var totalPages=Math.max(1,Math.ceil(total/size)), html='';for(var i=1;i<=Math.min(5,totalPages);i++)html+='<button class="page '+(i===page?'on':'')+'" data-page="'+i+'">'+i+'</button>';if(totalPages>5)html+='<span>...</span><button class="page" data-page="'+totalPages+'">'+totalPages+'</button>';html+='<button class="page" data-next="1">›</button>';p.innerHTML=html;$$('[data-page]').forEach(function(b){b.onclick=function(){page=num(b.dataset.page)||1;draw()}});var nx=$('[data-next]');if(nx)nx.onclick=function(){if(page<totalPages)page++;draw()}}
  function bindPickInputs(){$$('.pick').forEach(function(inp){inp.onchange=function(ev){safe(function(){if(typeof done==='undefined')done={};if(typeof hist!=='undefined')hist.push(JSON.stringify(done));if(typeof redo!=='undefined')redo=[];done[ev.target.dataset.k]=num(ev.target.value);if(typeof saveState==='function')saveState();draw()},'save picked')}})}
