    var choose=$('#choose'), file=$('#file');if(choose&&file){choose.onclick=function(){file.click()};file.addEventListener('change',function(){var x=file.files&&file.files[0];if(x)note(x.size>70*1024*1024?'ไฟล์ใหญ่มาก อาจช้าบนมือถือ '+Math.round(x.size/1024/1024)+'MB':'กำลังอ่านไฟล์: '+x.name)})}
    var ps=$('#psSelect'), st=$('#storeSelect'), br=$('#brandSelect'), ty=$('#typeSelect'), sd=$('#startDate'), ed=$('#endDate'), q=$('#q'), search=$('#searchBtn'), clear=$('#clearFilter'), reset=$('#resetDone'), copy=$('#copySummary'), exp=$('#exportCsv'), pick=$('#modePick'), raw=$('#rawTab'), dn=$('#doneTab');
    if(pick)pick.onclick=function(){view='pick';page=1;draw()};if(raw)raw.onclick=function(){view='raw';page=1;draw()};if(dn)dn.onclick=function(){view='done';page=1;draw()};
