    function dc(){dateMode='multi';datesSel=new Set();allDatesSafe().forEach(function(d){if((!sd.value||d>=sd.value)&&(!ed.value||d<=ed.value))datesSel.add(d)});cellsSel=new Set();store='';page=1;draw()}if(sd)sd.onchange=dc;if(ed)ed.onchange=dc;
